CREATE TABLE IF NOT EXISTS "__EFMigrationsHistory" (
    "MigrationId" character varying(150) NOT NULL,
    "ProductVersion" character varying(32) NOT NULL,
    CONSTRAINT "PK___EFMigrationsHistory" PRIMARY KEY ("MigrationId")
);

START TRANSACTION;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20251209072959_init') THEN
    CREATE TABLE "AbpAuditLogs" (
        "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
        "TenantId" integer,
        "UserId" bigint,
        "ServiceName" character varying(256),
        "MethodName" character varying(256),
        "Parameters" character varying(4096),
        "ReturnValue" text,
        "ExecutionTime" timestamp with time zone NOT NULL,
        "ExecutionDuration" integer NOT NULL,
        "ClientIpAddress" character varying(64),
        "ClientName" character varying(128),
        "BrowserInfo" character varying(512),
        "ExceptionMessage" character varying(1024),
        "Exception" character varying(2000),
        "ImpersonatorUserId" bigint,
        "ImpersonatorTenantId" integer,
        "CustomData" character varying(2000),
        CONSTRAINT "PK_AbpAuditLogs" PRIMARY KEY ("Id")
    );
    END IF;
END $EF$;

